71	static std::string getOperationName(const Record &def) {
72	  auto prefix = def.getValueAsDef("opDialect")->getValueAsString("name");
73	  auto opName = def.getValueAsString("opName");
74	  if (prefix.empty())
75	    return std::string(opName);
76	  return std::string(formatv("{0}.{1}", prefix, opName));
77	}
