79	static std::vector<const Record *>
80	getRequestedOpDefinitions(const RecordKeeper &records) {
81	  const Record *classDef = records.getClass("Op");
82	  if (!classDef)
83	    PrintFatalError("ERROR: Couldn't find the 'Op' class!\n");
84	
85	  Regex includeRegex(opIncFilter), excludeRegex(opExcFilter);
86	  std::vector<const Record *> defs;
87	  for (const auto &def : records.getDefs()) {
88	    if (!def.second->isSubClassOf(classDef))
89	      continue;
90	    // Include if no include filter or include filter matches.
91	    if (!opIncFilter.empty() &&
92	        !includeRegex.match(getOperationName(*def.second)))
93	      continue;
94	    // Unless there is an exclude filter and it matches.
95	    if (!opExcFilter.empty() &&
96	        excludeRegex.match(getOperationName(*def.second)))
97	      continue;
98	    defs.push_back(def.second.get());
99	  }
100	
101	  return defs;
102	}
