198	template <typename T>
199	static void emitNamedConstraint(const T &it, raw_ostream &os) {
200	  if (!it.name.empty())
201	    os << "| `" << it.name << "`";
202	  else
203	    os << "&laquo;unnamed&raquo;";
204	  os << " | " << it.constraint.getSummary() << "\n";
205	}
