229	static void emitAllTypesMatch(SpecEmitter &emitter, const AllTypesMatch &arg) {
230	  int i = 0;
231	  for (auto &name : arg.names) {
232	    if (i > 0) {
233	      emitter.os << (i == static_cast<int>(arg.names.size()) - 1 ? " and "
234	                                                                 : ", ");
235	    }
236	    emitter.os << ":code:`" << name << "`";
237	    i++;
238	  }
239	  emitter.os << " must have the same shape and element type ("
240	             << TileIRTy{arg.type} << ").\n";
241	}
