350	static void emitOperationConstraint(SpecEmitter &emitter,
351	                                    const OperationConstraint &constraint) {
352	  std::visit(
353	      overloaded{
354	          [&](const AllTypesMatch &arg) { emitAllTypesMatch(emitter, arg); },
355	          [&](const AllElementTypeMatch &arg) {
356	            emitAllElementTypeMatch(emitter, arg);
357	          },
358	          [&](const AnyTypeOf &arg) { emitAnyTypeOf(emitter, arg); },
359	          [&](const AllRanksMatch &arg) { emitAllRanksMatch(emitter, arg); },
360	          [&](const TypesMatchWith &arg) { emitTypesMatchWith(emitter, arg); },
361	          [&](const SameTypeOperands &arg) {
362	            emitSameTypeOperands(emitter, arg);
363	          },
364	          [&](const SameOperandsAndResultShape &arg) {
365	            emitSameOperandsAndResultShape(emitter, arg);
366	          },
367	          [&](const SameOperandsAndResultElementType &arg) {
368	            emitSameOperandsAndResultElementType(emitter, arg);
369	          },
370	          [&](const OperationTrait &arg) { emitOperationTrait(emitter, arg); }},
371	      constraint);
372	}
