453	/// Emit the signature of an operation.
454	static void emitOperationSignature(SpecEmitter &emitter,
455	                                   const CudaTileOp &cuda_tile_op) {
456	  auto &signature = cuda_tile_op.signature;
457	  // if (op.hasAssemblyFormat()) {
458	  //   auto raw_signature = covertSyntaxToSignature(op);
459	  //   emitter.emitCodeBlock([&](raw_ostream &os) {
460	  //     os << signature.name << " ";
461	  //     for (auto &parameter : raw_signature) {
462	  //       os << parameter << " ";
463	  //     }
464	  //   });
465	  // } else {
466	  emitter.emitCodeBlock([&](raw_ostream &os) {
467	    os << signature.name << " ";
468	    for (auto &parameter : signature.parameters) {
469	      os << "%" << parameter.name << " ";
470	    }
471	  });
472	  //}
473	
474	  emitter.os << Header(OP_DETAILS_HEADER_LEVEL, "Parameters");
475	
476	  if (signature.parameters.empty()) {
477	    emitter.os << "No parameters.\n";
478	  }
479	
480	  for (auto &parameter : signature.parameters) {
481	    emitter.os << "- **" << parameter.name << "**";
482	    emitter.os << " (" << parameter.getTypeDescription() << ")";
483	    emitter.os << " - " << parameter.getDescription();
484	    if (!parameter.sinceVersion.empty()) {
485	      emitter.os << " " << Badge::successLine(parameter.sinceVersion);
486	    }
487	    emitter.os << "\n";
488	  }
489	
490	  emitter.os << "\n\n";
491	
492	  emitter.os << Header(OP_DETAILS_HEADER_LEVEL, "Results");
493	
494	  if (signature.results.empty()) {
495	    emitter.os << "No results.\n";
496	  }
497	
498	  for (auto &parameter : signature.results) {
499	    // TODO: Figure out how to ignore "spelling errors" in code names.
500	    // Ignore spell checks on parameter/result names
501	    // emitter.os << "- :spelling:ignore:`**" << parameter.name << "**`";
502	    emitter.os << "- **" << parameter.name << "**";
503	    emitter.os << " (" << parameter.getTypeDescription() << ")";
504	    emitter.os << " - " << parameter.getDescription();
505	
506	    if (!parameter.sinceVersion.empty()) {
507	      emitter.os << " " << Badge::successLine(parameter.sinceVersion);
508	    }
509	
510	    emitter.os << "\n";
511	  }
512	
513	  emitter.os << "\n\n";
514	}
