53	      {"HasOnlyGraphRegion",
54	       "The operation must contain only dataflow graph regions."},
55	      {"FunctionOpInterface",
56	       "The operation must implement function-like behavior interface."},
57	      {"CallOpInterface", "The operation must implement call interface."},
58	      {"CallableOpInterface",
59	       "The operation must implement callable target interface."},
60	      {"Symbol", "The operation must be a symbol in the global symbol table."},
61	      {"SymbolTable", "The operation must define a symbol scope."},
62	      {"OpAsmOpInterface",
63	       "The operation must provide custom parsing and printing methods."},
64	      {"AttrSizedOperandSegments", "The operation must encode variadic operand "
65	                                   "segment sizes in attributes."},
66	      {"Elementwise", "The operation must apply element-wise to its operands."},
67	      {"SameOperandsShape", "All operands must have identical shapes."},
68	      {"Terminator", "The operation must terminate its parent basic block."},
69	      {"RegionKindInterface",
70	       "The operation must specify whether regions are SSACFG or Graph kind."},
71	      {"MemoryEffectOpInterface",
72	       "The operation must declare its memory effects."},
73	      {"Pure",
74	       "The operation has no side effects and may be speculatively executed."},
75	      {"SameOperandsAndResultType",
76	       "The operation's operands and results all have the same type."}};
77	
78	  auto it = traitMap.find(traitName);
79	  if (it != traitMap.end()) {
80	    return it->second;
81	  }
82	  return std::nullopt;
83	}
