96	TileIRType OperationParameter::getTypeDescription() const {
97	  switch (type) {
98	  case kArgument: {
99	    if (!typeConstraint) {
100	      llvm_unreachable("Type constraint is missing");
101	    }
102	
103	    auto tcDef = this->typeConstraint->getDef();
104	    return getType(tcDef);
105	  }
106	  case kAttribute: {
107	    if (!attribute) {
108	      llvm_unreachable("Attribute is missing");
109	    }
110	
111	    return convertAttribute(this->opName, *attribute);
112	  }
113	  case kProperty: {
114	    if (!property) {
115	      llvm_unreachable("Property is missing");
116	    }
117	
118	    PrintFatalError("Property descriptions are not supported yet. Failed while "
119	                    "processing: " +
120	                    this->opName + "." + this->name);
121	  }
122	  default:
123	    llvm_unreachable("Invalid parameter type");
124	  }
125	}
