137	static std::vector<OperationConstraint>
138	getOperationConstraints(const mlir::tblgen::Operator &op,
139	                        OperationSignature &signature) {
140	  std::vector<OperationConstraint> constraints;
141	
142	  llvm::errs() << "Processing operation: " << op.getOperationName() << "\n";
143	
144	  for (auto trait : op.getTraits()) {
145	    const auto &def = trait.getDef();
146	
147	    if (def.isSubClassOf("AllTypesMatch")) {
148	      llvm::errs() << "Processing AllTypesMatch trait\n";
149	      auto values = def.getValueAsListOfStrings("values");
150	      std::vector<std::string> names;
151	      std::string type;
152	      for (auto val : values) {
153	        std::string nameStr = val.str();
154	        names.push_back(nameStr);
155	
156	        if (auto parameter = signature.getParamOrResult(nameStr)) {
157	          std::string paramType = parameter->getTypeDescription().toString();
158	
159	          if (type.empty()) {
160	            type = paramType;
161	          } else if (type != paramType) {
162	            // Skip type constraint check if one of the types is DenseConstant
163	            if (type == "DenseConstant" ||
164	                paramType.find("DenseConstant") != std::string::npos) {
165	              continue;
166	            }
167	
168	            llvm::errs() << "Type constraint mismatch detected for name \""
169	                         << nameStr << "\":\n"
170	                         << "  Expected based on previous: " << type << "\n"
171	                         << "  Got: " << paramType << "\n";
172	            assert(false && "AllTypesMatch: Type constraint mismatch.");
173	          }
174	        }
175	      }
176	      constraints.push_back(OperationConstraint(AllTypesMatch{names, type}));
177	    } else if (def.isSubClassOf("AllElementTypeMatch")) {
178	      llvm::errs() << "Processing AllElementTypeMatch trait\n";
179	      auto values = def.getValueAsListOfStrings("values");
180	      std::vector<std::string> names;
181	      std::string type;
182	      for (auto val : values) {
183	        std::string nameStr = val.str();
184	        names.push_back(nameStr);
185	
186	        if (auto parameter = signature.getParamOrResult(nameStr)) {
187	          std::string paramType = parameter->getTypeDescription().toString();
188	
189	          if (type.empty()) {
190	            type = paramType;
191	          } else if (type != paramType) {
192	            // Skip type constraint check if one of the types is DenseConstant
193	            if (type == "DenseConstant" ||
194	                paramType.find("DenseConstant") != std::string::npos) {
195	              continue;
196	            }
197	
198	            llvm::errs() << "Type constraint mismatch detected for name \""
199	                         << nameStr << "\":\n"
200	                         << "  Expected based on previous: " << type << "\n"
201	                         << "  Got: " << paramType << "\n";
202	            assert(false && "AllTypesMatch: Type constraint mismatch.");
203	          }
204	        }
205	      }
206	      constraints.push_back(
207	          OperationConstraint(AllElementTypeMatch{names, type}));
208	    } else if (def.isSubClassOf("TypesMatchWith")) {
209	      llvm::errs() << "Processing TypesMatchWith trait\n";
210	      auto *summaryVal = def.getValue("summary");
211	      assert(summaryVal &&
212	             "TypesMatchWith: Trait must have a 'summary' field.");
213	      auto *stringInit =
214	          llvm::dyn_cast<llvm::StringInit>(summaryVal->getValue());
215	      assert(stringInit &&
216	             "TypesMatchWith: 'summary' field must be a StringInit.");
217	      constraints.push_back(
218	          OperationConstraint(TypesMatchWith{stringInit->getValue().str()}));
219	
220	    } else if (def.isSubClassOf("AnyTypeOf")) {
221	      llvm::errs() << "Processing AnyTypeOf trait\n";
222	      constraints.push_back(
223	          OperationConstraint(AnyTypeOf{getTraitValueNames(def)}));
224	
225	    } else if (def.isSubClassOf("AllRanksMatch")) {
226	      llvm::errs() << "Processing AllRanksMatch trait\n";
227	      constraints.push_back(
228	          OperationConstraint(AllRanksMatch{getTraitValueNames(def)}));
229	
230	    } else if (def.getName() == "SameOperandsAndResultElementType") {
231	      llvm::errs() << "Processing SameOperandsAndResultElementType trait\n";
232	      std::vector<std::string> names, types;
233	      for (auto param : signature.parameters) {
234	        names.push_back(param.name);
235	        types.push_back(param.getTypeDescription().toString());
236	      }
237	      for (auto param : signature.results) {
238	        names.push_back(param.name);
239	        types.push_back(param.getTypeDescription().toString());
240	      }
241	      if (!types.empty()) {
242	        assert(
243	            std::all_of(types.begin() + 1, types.end(),
244	                        [&](const std::string &t) { return t == types[0]; }) &&
245	            "All types must be identical");
246	      }
247	      constraints.push_back(OperationConstraint(
248	          SameOperandsAndResultElementType{names, types[0]}));
249	
250	    } else if (def.getName() == "SameTypeOperands") {
251	      llvm::errs() << "Processing SameTypeOperands trait\n";
252	      std::vector<std::string> names;
253	      std::vector<std::string> types;
254	      for (auto param : signature.parameters) {
255	        names.push_back(param.name);
256	        types.push_back(param.getTypeDescription().toString());
257	      }
258	      if (!types.empty()) {
259	        assert(
260	            std::all_of(types.begin() + 1, types.end(),
261	                        [&](const std::string &t) { return t == types[0]; }) &&
262	            "All types must be identical");
263	      }
264	      constraints.push_back(
265	          OperationConstraint(SameTypeOperands{names, types[0]}));
266	    } else if (def.getName() == "SameOperandsAndResultShape") {
267	      llvm::errs() << "Processing SameOperandsAndResultShape trait\n";
268	      std::vector<std::string> names;
269	      for (auto param : signature.parameters) {
270	        names.push_back(param.name);
271	      }
272	      for (auto param : signature.results) {
273	        names.push_back(param.name);
274	      }
275	      constraints.push_back(
276	          OperationConstraint(SameOperandsAndResultShape{names}));
277	    } else {
278	      std::string traitName = def.getName().str();
279	      auto traitConstraint = getTraitConstraint(traitName);
280	      if (traitConstraint)
281	        constraints.push_back(
282	            OperationConstraint(OperationTrait{*traitConstraint}));
283	    }
284	  }
285	
286	  return constraints;
287	}
