289	OperationSignature::OperationSignature(const mlir::tblgen::Operator &op) {
290	  auto opName = op.getOperationName();
291	  this->name = op.getOperationName();
292	  this->parameters = std::vector<OperationParameter>();
293	  this->parameterMap = std::unordered_map<std::string, OperationParameter>();
294	
295	  for (int i = 0; i < op.getNumArgs(); i++) {
296	    auto arg = op.getArg(i);
297	    auto argDecorators = op.getArgDecorators(i);
298	
299	    std::string parameterName;
300	    std::optional<TypeConstraint> typeConstraint;
301	    std::optional<Attribute> attribute;
302	    std::optional<Property> property;
303	
304	    ParameterType parameterType;
305	
306	    if (auto *namedTypeConstraint = arg.dyn_cast<NamedTypeConstraint *>()) {
307	      parameterName = namedTypeConstraint->name;
308	      typeConstraint = namedTypeConstraint->constraint;
309	      parameterType = kArgument;
310	    } else if (auto *namedAttr = arg.dyn_cast<NamedAttribute *>()) {
311	      parameterName = namedAttr->name;
312	      attribute = namedAttr->attr;
313	      parameterType = kAttribute;
314	    } else if (auto *namedProperty = arg.dyn_cast<NamedProperty *>()) {
315	      parameterName = namedProperty->name;
316	      property = namedProperty->prop;
317	      parameterType = kProperty;
318	    } else {
319	      llvm_unreachable("Statically impossible pointer type.");
320	    }
321	
322	    std::string sinceVersion;
323	    std::string specDesc;
324	    std::optional<std::vector<std::string>> selectedVariants = std::nullopt;
325	
326	    for (auto argDecorator : argDecorators) {
327	      if (argDecorator.getDef().isSubClassOf("CudaTileArgMetadata")) {
328	        sinceVersion = argDecorator.getDef().getValueAsString("sinceVersion");
329	        specDesc = argDecorator.getDef().getValueAsString("specDesc");
330	      }
331	      if (argDecorator.getDef().isSubClassOf("OnlyVariants")) {
332	        std::cout << "Processing OnlyVariants decorator" << std::endl;
333	        auto variants =
334	            argDecorator.getDef().getValueAsListOfStrings("variants");
335	        std::vector<std::string> foundSelectedVariants;
336	        for (auto variant : variants) {
337	          std::cout << "variant: " << variant.str() << std::endl;
338	          foundSelectedVariants.push_back(variant.str());
339	        }
340	        selectedVariants = foundSelectedVariants;
341	      }
342	    }
343	
344	    parameters.push_back({opName, parameterName, sinceVersion, specDesc,
345	                          typeConstraint, attribute, property, selectedVariants,
346	                          parameterType});
347	  }
348	
349	  for (int i = 0; i < op.getNumResults(); i++) {
350	    auto result = op.getResult(i);
351	    auto resultDecorators = op.getResultDecorators(i);
352	
353	    std::string resultName;
354	    std::optional<TypeConstraint> typeConstraint;
355	    std::optional<Attribute> attribute;
356	    std::optional<Property> property;
357	
358	    ParameterType parameterType = kArgument;
359	
360	    resultName = result.name;
361	    typeConstraint = result.constraint;
362	
363	    std::string sinceVersion;
364	    std::string specDesc;
365	    std::optional<std::vector<std::string>> selectedVariants = std::nullopt;
366	
367	    for (auto resultDecorator : resultDecorators) {
368	      if (resultDecorator.getDef().isSubClassOf("CudaTileArgMetadata")) {
369	        sinceVersion =
370	            resultDecorator.getDef().getValueAsString("sinceVersion");
371	        specDesc = resultDecorator.getDef().getValueAsString("specDesc");
372	      }
373	      if (resultDecorator.getDef().isSubClassOf("OnlyVariants")) {
374	        auto variants =
375	            resultDecorator.getDef().getValueAsListOfStrings("variants");
376	        std::vector<std::string> foundSelectedVariants;
377	        for (auto variant : variants) {
378	          foundSelectedVariants.push_back(variant.str());
379	        }
380	        selectedVariants = foundSelectedVariants;
381	      }
382	    }
383	
384	    results.push_back({opName, resultName, sinceVersion, specDesc,
385	                       typeConstraint, attribute, property, selectedVariants,
386	                       parameterType});
387	  }
388	
389	  for (auto &param : parameters) {
390	    this->parameterMap.insert({param.name, param});
391	  }
392	
393	  for (auto &param : results) {
394	    this->parameterMap.insert({param.name, param});
395	  }
396	
397	  this->constraints = getOperationConstraints(op, *this);
398	}
