442	static Table getTableFromRecord(const Record *tableDef) {
443	  std::vector<TableHeader> headers;
444	  std::vector<TableRow> rows;
445	
446	  std::string label = tableDef->getValueAsString("label").str();
447	  std::string description = tableDef->getValueAsString("description").str();
448	  std::optional<std::string> oDescription = std::nullopt;
449	
450	  if (!description.empty()) {
451	    oDescription = description;
452	  }
453	
454	  auto headerDefs = tableDef->getValueAsListOfDefs("headers");
455	
456	  for (auto headerDef : headerDefs) {
457	    std::string label = headerDef->getValueAsString("label").str();
458	    std::string contentType = headerDef->getValueAsString("contentType").str();
459	
460	    ColumnFormatType format;
461	    if (contentType == "code") {
462	      format = ColumnFormatType::kCode;
463	    } else {
464	      format = ColumnFormatType::kText;
465	    }
466	
467	    int width = headerDef->getValueAsInt("width");
468	    std::optional<int> oWidth =
469	        width == -1 ? std::nullopt : std::optional<int>(width);
470	
471	    headers.emplace_back(label, oWidth, format);
472	  }
473	
474	  auto rowDefs = tableDef->getValueAsListOfDefs("rows");
475	  for (auto rowDef : rowDefs) {
476	    std::vector<std::string> entries;
477	    for (auto entryDef : rowDef->getValueAsListOfStrings("columns")) {
478	      entries.push_back(entryDef.str());
479	    }
480	    rows.push_back(TableRow{entries});
481	  }
482	
483	  // We now have all the headers and the rows, create the table.
484	  return Table{label, oDescription, headers, rows, {}};
485	}
486	
487	std::vector<Table> CudaTileOp::getDescriptionTables() {
488	  auto def = this->op.getDef();
489	  auto tableDefs = def.getValueAsListOfDefs("descriptionTables");
490	
491	  std::vector<Table> tables;
492	  tables.reserve(tableDefs.size());
493	  // For each table definition, create a table.
494	  for (auto tableDef : tableDefs) {
495	    tables.push_back(getTableFromRecord(tableDef));
496	  }
497	
498	  return tables;
499	}
