504	
505	std::vector<TileIRAttr> CudaTileOp::getAttributes() {
506	  std::vector<TileIRAttr> attributes;
507	  std::unordered_set<std::string> processedAttributes;
508	
509	  for (const auto &it : this->op.getAttributes()) {
510	    const Record *record = &it.attr.getDef();
511	
512	    auto attributeName = it.attr.getAttrDefName().str();
513	    std::cout << "Processing attribute: " << attributeName << std::endl;
514	    // In the case that we have multiple operands with the same attribute type
515	    // we only want to generate documentation for the attribute type itself
516	    // once.
517	    if (processedAttributes.find(attributeName) != processedAttributes.end()) {
518	      continue;
519	    }
520	
521	    // Strip off the DefaultValuedAttr first.
522	    if (record->isSubClassOf("DefaultValuedAttr") ||
523	        record->isSubClassOf("OptionalAttr")) {
524	      record = record->getValueAsDef("baseAttr");
525	    }
526	
527	    // Check for a bare enum value first.
528	    if (record->isSubClassOf("CudaTileI32EnumAttr") ||
529	        record->isSubClassOf("CudaTileI64EnumAttr")) {
530	      auto param = this->signature.getParamOrResult(it.name.str());
531	      auto enumAttr = TileIREnumAttr::fromTableGen(
532	          this->op.getOperationName(), *record, param->selectedVariants);
533	      attributes.emplace_back(enumAttr);
534	      // Then check to see if it's an cuda tile enum attr.
535	    } else if (record->isSubClassOf("CudaTileEnumAttr")) {
536	      std::cout << "Processing CudaTileEnumAttr" << std::endl;
537	      std::cout << "it.name: " << it.name.str() << std::endl;
538	      auto param = this->signature.getParamOrResult(it.name.str());
539	      auto enumInfoRecord = record->getValueAsDef("enum");
540	      auto enumAttr = TileIREnumAttr::fromTableGen(this->op.getOperationName(),
541	                                                   *enumInfoRecord,
542	                                                   param->selectedVariants);
543	      attributes.emplace_back(enumAttr);
544	    } else if (record->isSubClassOf("CudaTileAttrDef")) {
545	      auto attrDef =
546	          TileIRAttrDef::fromTableGen(this->op.getOperationName(), *record);
547	      attributes.emplace_back(attrDef);
548	    } else if (record->isSubClassOf("AttrInterface")) {
549	      auto name = record->getName();
550	      // Remove the "CudaTile_" prefix from the attribute name if present.
551	      static const std::string prefix = "CudaTile_";
552	      if (name.starts_with(prefix)) {
553	        name = name.substr(prefix.size());
554	      }
555	      static const std::string suffix = "AttrInterface";
556	      if (name.ends_with(suffix)) {
557	        name = name.substr(0, name.size() - suffix.size());
558	      }
559	
560	      auto attrInterface =
561	          TileIRAttrInterface{this->op.getOperationName(), name.str(), "", ""};
562	      attributes.emplace_back(attrInterface);
563	    }
564	
565	    processedAttributes.insert(attributeName);
566	  }
567	  return attributes;
568	}
