129	      : description(std::move(description)) {}
130	};
131	
132	using OperationConstraint =
133	    std::variant<AllTypesMatch, AllElementTypeMatch, SameOperandsAndResultShape,
134	                 TypesMatchWith, AnyTypeOf, SameOperandsAndResultElementType,
135	                 AllRanksMatch, SameTypeOperands, OperationTrait>;
136	
137	struct OperationSignature {
138	  std::string name;
139	  std::vector<OperationParameter> parameters;
140	  std::vector<OperationParameter> results;
141	  std::vector<OperationConstraint> constraints;
142	  // This copies for now but we could optimize if it matters.
143	  std::unordered_map<std::string, OperationParameter> parameterMap;
144	
